var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"탄창!","JPN":"弾倉！","ENG":"Ammo!","TWN":"彈匣！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"말해 두겠는데, 이제 세 개 남았다.","JPN":"言っておくが、残りはあと3つだ。","ENG":"Just so you know, there’s only three mags left.","TWN":"現在就剩三個了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"제기랄. 저놈들 끝이 없어 보이는데. ","JPN":"クソ、キリがないな。","ENG":"Damn... There’s no end to them. ","TWN":"可惡！那些傢伙看起來沒完沒了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L9_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이상해. 여기에 이렇게 많은 침식체가 있을 리 없어.","JPN":"なにかおかしい。ここにこんな侵食体が多いはずがない。","ENG":"Something is off. There’s no way there'd be so many C.O.'s here.","TWN":"太奇怪了， 這裡不可能有這麼多的侵蝕體啊。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 있잖아?","JPN":"でも、実際にいるじゃねえか？","ENG":"You know what, though?","TWN":"但事實就是如此。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"윗대가리 놈들, 굳이 우릴 여기에 보낸 걸 보면 뭔가 알고 있었던 거 아냐?","JPN":"わざわざ俺らをここへ向かわせたってことは、お偉いさんたちは何か知ってたんじゃないのか？","ENG":"The top brass must’ve known something if they dispatched us all the way out here.","TWN":"上頭非要把我們送到這裡，難道他們早有什麼打算了？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......뭐, 그렇겠지. 우리에게 친절하게 설명해 줄 이유는 없으니까.","JPN":"……まあ、そうだろうな。だが企業のやつらは、わざわざ俺たちに説明する理由がない。","ENG":"I bet. And they had no reason to explain everything to us either.","TWN":"……也許。 畢竟他們也沒有理由給我們詳細地說明。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"......개자식들.","JPN":"……ちくしょう。","ENG":"Those bastards.","TWN":"……這群雜碎！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"수다 시간은 끝이다!","JPN":"おしゃべりはもう十分だ！","ENG":"Enough chatting!","TWN":"聊天時間結束了！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"어이! 수리는 멀었나?","JPN":"おい！　修理はまだか？","ENG":"Hey! Are we there yet?","TWN":"喂！還沒好嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......내 전공은 통신병이 아니라 다른 놈들 대가리에 총알 박아 넣는 거거든?!","JPN":"……私の専門は通信じゃなくて、撃つことなの！","ENG":"I’m not a radioman by trade... I specialize in putting bullets in skulls, alright?","TWN":"……我的專業不是通訊兵，而是把子彈打進那些傢伙的腦袋裡！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"전공 살리기 전에 좀 닥쳐 줄래?!","JPN":"頭、ぶち抜かれたくなかったら黙ってて！","ENG":"So shut up before I decide to practice my specialty on you!","TWN":"在我發揮我的專業前先閉嘴好嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"제기랄!","JPN":"クソ！","ENG":"Damn it!","TWN":"可惡！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래도 정기 연락이 끊겼으니까 접선지에서 기다리던 카운터가 이쪽으로 오고 있을 거야!","JPN":"定期連絡が途切れたんだ、合流地点で待機してるカウンターがこっちへ向かうはずだろ！","ENG":"Still, they must've realized something went wrong when we stopped calling in. Maybe the Counter is on the way here from the rendezvous point?","TWN":"定期聯絡斷了，在會合處等待的制裁者應該會往這邊來的！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"카운터가 오면 해 볼 만하지 않을까?","JPN":"カウンターが来れば、どうにかなるだろ！？","ENG":"We might have a shot with a Counter here, no?","TWN":"制裁者來了的話，應該能拼一下吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......생각 없는 놈은 행복해서 좋겠군.","JPN":"……バカはのんきで羨ましいな。","ENG":"Ignorance is bliss, I guess...","TWN":"……真羡慕你們這些沒腦袋的傻瓜。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐?","JPN":"はあ？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"눈이 있으면 봐라. 저놈들이 어느 방향에서 오는지.","JPN":"お前の目は節穴か？　侵食体が来た方向を見ろ。","ENG":"If you’ve got eyes, use them. Look where they’re coming from.","TWN":"睜大眼睛，好好看看那些傢伙是從哪個方向來的。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"접선지가 저쪽 방향인데 카운터가 살아 있으면 침식체가 저기서 기어 나오고 있겠냐?","JPN":"合流地点はあっちだ。カウンターが生きてたら、あそこから侵食体が湧いてくるはずないだろ？","ENG":"The rendezvous point was that way. You think the C.O.'s would be swarming from over there if our Counter was still alive?","TWN":"會合地點就是那個方向，如果制裁者還活著的話，侵蝕體還會從那邊爬出來嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"아...... 젠장!","JPN":"あ……クソ！","ENG":"Oh... Damn it!","TWN":"啊……該死！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그러게 좀 실력 있는 놈 쓰자니까...... 그 돈 아껴서 무슨 부귀영화를 누리겠다고.","JPN":"だから腕のいいやつを雇えって言っただろうが……、ケチって死ぬとか笑えないぜ。","ENG":"This is why I told them we have to get someone good! Those stingy bastards are gonna get us killed.","TWN":"當初就說要用有實力的人了……省那點錢是能幹嘛啦。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......별 수 없지.","JPN":"……仕方ない。","ENG":"Oh well.","TWN":"……沒辦法了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이제 먹히면서 죽을지, 먹히기 전에 죽을지나 빨리 선택하는 게 나을 것 같은데.","JPN":"食われて死ぬか、食われる前に死ぬか、早く選んだ方がよさそうだ。","ENG":"I guess we’ll just have to decide whether we’ll let them eat us alive or try to die before they get to us.","TWN":"現在我們最好開始選是要被吃時死掉，還是被吃之前死掉吧。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"잠깐!","JPN":"おい！","ENG":"Wait!","TWN":"等等！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐, 사람 언젠가 죽기 마련 아닌가?","JPN":"どうせ人は、いつか死ぬんだ。","ENG":"I mean, we’re all going to die eventually, right?","TWN":"人不是總有一死嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이 바닥에 온 이상 너도 죽을 건 예상하고......","JPN":"この業界に足を踏み入れた以上、お前だって死を覚悟……","ENG":"Surely you didn’t think you’d die of old age when you set foot into this line of business...","TWN":"既然都來到這裡，你應該早就預料會有死的可能……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그게 아니라!","JPN":"そうじゃなくて！","ENG":"No, that’s not what I’m talking about!","TWN":"不是！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"저쪽에 사람이 있어!","JPN":"あっちに人がいる！","ENG":"There's a person over there!","TWN":"我是說那邊有人！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"응? 그럴 리가......?","JPN":"は？　そんなはずないだろ……？","ENG":"Huh? That can’t be...","TWN":"嗯？怎麼可能……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"이쪽 방향으로 오는데? 혹시 회사가 고용했다던 카운터인가?","JPN":"こっちへ向かってるぞ？　もしかして、会社が雇ったカウンターか？","ENG":"She is coming this way... Could that be the Counter the company hired?","TWN":"好像在往這邊來，難道是公司雇傭的制裁者嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"아니. 다가오는 방향이 전혀 달라.","JPN":"いや、方向がまったく逆だ。","ENG":"No. She is coming from a completely different direction.","TWN":"不是，她向我們接近的方向完全不對。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래도 젠장! 어쨌든 카운터잖아?!!","JPN":"クソ！　でも、とにかくカウンターだろ！？","ENG":"Ugh, who cares! It’s still a Counter, right?","TWN":"管他的！ 總之是個制裁者吧？！！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래. 그게 중요한 점이라는 건 나도 인정한다!","JPN":"ああ、それが重要だってことは俺も認める！","ENG":"Right. I agree that’s the important thing here!","TWN":"對，我也承認這很重要！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"뭐야? 힘들어 죽겠는데?","JPN":"何？　今、集中してるのに！","ENG":"What? I’m working my ass off!","TWN":"我都快累死了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"지금 이게 마지막 기회다!","JPN":"これが最後のチャンスだ！","ENG":"This is our last chance!","TWN":"現在是最後的機會了！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"총 잡아! 신원미상의 카운터와 함께 침식체를 요격한다!","JPN":"銃を構えろ！　身元不明のカウンターと一緒に、侵食体を迎撃する！","ENG":"Grab your guns! We’ll take down the C.O.'s along with our mystery Counter!","TWN":"拿起槍！和新來的制裁者一起擊退侵蝕體！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};